import React from "react";

/* ── Signal pulse SVG ──────────────────────────────────────────────
   A single EKG-style heartbeat line. Drawn on load via CSS stroke
   animation. Signature element of the design.
───────────────────────────────────────────────────────────────────── */
function SignalPulse() {
  return (
    <svg
      viewBox="0 0 600 60"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
      className="w-full max-w-2xl"
      style={{ height: "60px", overflow: "visible" }}
    >
      <polyline
        className="signal-line"
        points="
          0,30
          120,30
          150,30
          165,8
          180,52
          195,15
          210,45
          225,30
          260,30
          600,30
        "
        fill="none"
        stroke="#C8FF57"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/* ── Nav bar ───────────────────────────────────────────────────────── */
function Nav() {
  const links = [
    { href: "#builds", label: "What I Build" },
    { href: "#demos", label: "Demos" },
    { href: "#testimonials", label: "Testimonials" },
    { href: "#contact", label: "Contact" }
  ];

  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-6 md:px-12"
      style={{
        height: "60px",
        background: "rgba(10, 10, 15, 0.85)",
        backdropFilter: "blur(12px)",
        borderBottom: "1px solid #2C2C3E"
      }}
    >
      {/* Logo / name */}
      <span
        style={{
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: "0.75rem",
          letterSpacing: "0.06em",
          color: "#F0F0EC"
        }}
      >
        yair berger
      </span>

      {/* Links */}
      <ul className="hidden md:flex items-center gap-8 list-none">
        {links.map((l) => (
          <li key={l.href}>
            <a href={l.href} className="nav-link">
              {l.label}
            </a>
          </li>
        ))}
      </ul>

      {/* Mobile CTA */}
      <a
        href="#contact"
        className="md:hidden"
        style={{
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: "0.65rem",
          letterSpacing: "0.1em",
          textTransform: "uppercase",
          color: "#C8FF57"
        }}
      >
        Contact →
      </a>
    </nav>
  );
}

/* ── Hero ──────────────────────────────────────────────────────────── */
export default function Hero() {
  return (
    <>
      <Nav />

      <section
        id="hero"
        className="section flex flex-col justify-center"
        style={{
          minHeight: "100vh",
          paddingTop: "8rem",
          paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
          paddingRight: "clamp(1.5rem, 8vw, 8rem)"
        }}
      >
        {/* Eyebrow */}
        <p className="eyebrow mb-6">Global Digital Marketing Lead · AI Systems Builder</p>

        {/* Headline */}
        <h1
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(3rem, 7.5vw, 6rem)",
            fontWeight: 700,
            lineHeight: 1.02,
            letterSpacing: "-0.035em",
            color: "#F0F0EC",
            maxWidth: "14ch"
          }}
        >
          I build AI systems that run.
        </h1>

        {/* Signal pulse — the signature element */}
        <div className="my-8">
          <SignalPulse />
        </div>

        {/* Subline */}
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "clamp(1rem, 2.2vw, 1.25rem)",
            color: "#8A8A9A",
            maxWidth: "52ch",
            lineHeight: 1.6
          }}
        >
          Agentic pipelines, LLM evaluation frameworks, and automation
          that teams actually depend on.
        </p>

        {/* CTAs */}
        <div className="flex flex-wrap gap-4 mt-10">
          <a
            href="#demos"
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "0.5rem",
              fontFamily: "'Space Grotesk', sans-serif",
              fontWeight: 600,
              fontSize: "0.95rem",
              background: "#C8FF57",
              color: "#0A0A0F",
              padding: "0.75rem 1.75rem",
              borderRadius: "0.375rem",
              textDecoration: "none",
              transition: "opacity 0.15s ease"
            }}
            onMouseEnter={e => e.currentTarget.style.opacity = "0.88"}
            onMouseLeave={e => e.currentTarget.style.opacity = "1"}
          >
            See live demos →
          </a>

          <a
            href="#contact"
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "0.5rem",
              fontFamily: "'Space Grotesk', sans-serif",
              fontWeight: 500,
              fontSize: "0.95rem",
              background: "transparent",
              color: "#F0F0EC",
              padding: "0.75rem 1.75rem",
              border: "1px solid #2C2C3E",
              borderRadius: "0.375rem",
              textDecoration: "none",
              transition: "border-color 0.15s ease"
            }}
            onMouseEnter={e => e.currentTarget.style.borderColor = "#8A8A9A"}
            onMouseLeave={e => e.currentTarget.style.borderColor = "#2C2C3E"}
          >
            Get in touch
          </a>
        </div>

        {/* Scroll nudge */}
        <div
          className="absolute bottom-10 left-1/2"
          style={{ transform: "translateX(-50%)" }}
          aria-hidden="true"
        >
          <div
            style={{
              width: "1px",
              height: "48px",
              background: "linear-gradient(to bottom, #2C2C3E, transparent)",
              margin: "0 auto"
            }}
          />
        </div>
      </section>
    </>
  );
}
